wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(6303023903742203)
,p_plug_name=>'Hospital Overview'
,p_static_id=>'new'
,p_title=>'Hospital Overview'
,p_region_template_options=>'#DEFAULT#:t-CardsRegion--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2074200852440250129
,p_plug_display_sequence=>20
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ''Total Patients''       AS CARD_TITLE,',
'       TO_CHAR(COUNT(*))      AS CARD_VALUE,',
'       ''fa-users''             AS CARD_ICON,',
'       ''u-color-9''            AS CARD_COLOR',
'FROM   PATIENTS',
'UNION ALL',
'SELECT ''Today''''s Appointments'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-calendar-check-o'',',
'       ''u-color-5''',
'FROM   APPOINTMENTS',
'WHERE  TRUNC(APPOINTMENT_DATE) = TRUNC(SYSDATE)',
'UNION ALL',
'SELECT ''Active Doctors'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-stethoscope'',',
'       ''u-color-7''',
'FROM   DOCTORS',
'WHERE  STATUS = ''Active''',
'UNION ALL',
'SELECT ''Current Admissions'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-hospital-o'',',
'       ''u-color-3''',
'FROM   ADMISSIONS',
'WHERE  STATUS = ''Admitted''',
'UNION ALL',
'SELECT ''Low Stock Medicines'',',
'       TO_CHAR(COUNT(*)),',
'       ''fa-warning'',',
'       ''u-color-1''',
'FROM   MEDICINES',
'WHERE  CURRENT_STOCK < REORDER_LEVEL'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows_type=>'SCROLL'
,p_show_total_row_count=>false
,p_created_on=>wwv_flow_imp.dz('20260713055206Z')
,p_updated_on=>wwv_flow_imp.dz('20260717135758Z')
,p_created_by=>'ADMIN'
,p_updated_by=>'ADMIN'
);
