,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Save Appointment Record'
,p_static_id=>'save-appointment-record'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'    IF :P8_APPOINTMENT_ID IS NULL THEN',
'        INSERT INTO APPOINTMENTS',
'            (PATIENT_ID, DOCTOR_ID, APPOINTMENT_DATE,',
'             APPOINTMENT_TIME, STATUS_ID, REASON_FOR_VISIT)',
'        VALUES',
'            (:P8_PATIENT_ID, :P8_DOCTOR_ID, :P8_APPOINTMENT_DATE,',
'             :P8_APPOINTMENT_TIME, :P8_STATUS_ID, :P8_REASON_FOR_VISIT);',
'    ELSE',
'        UPDATE APPOINTMENTS SET',
'            PATIENT_ID       = :P8_PATIENT_ID,',
'            DOCTOR_ID        = :P8_DOCTOR_ID,',
'            APPOINTMENT_DATE = :P8_APPOINTMENT_DATE,',
'            APPOINTMENT_TIME = :P8_APPOINTMENT_TIME,',
'            STATUS_ID        = :P8_STATUS_ID,',
'            REASON_FOR_VISIT = :P8_REASON_FOR_VISIT',
'        WHERE APPOINTMENT_ID = :P8_APPOINTMENT_ID;',
'    END IF;',
'    COMMIT;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_process_error_message=>'An error occurred while saving appointment. Appointment saved Unsuccessful.'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
