wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(8892516083128221)
,p_plug_name=>'Appointment History'
,p_static_id=>'appointments'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>50
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    a.APPOINTMENT_ID,',
'    a.PATIENT_ID,',
'    a.DOCTOR_ID,',
'    a.APPOINTMENT_DATE,',
'    a.APPOINTMENT_TIME,',
'    a.STATUS_ID,',
'    a.REASON_FOR_VISIT,',
'    CASE',
'      WHEN s.STATUS_NAME <> ''Cancelled'' AND v.VISIT_ID IS NULL THEN',
'        ''<a class="t-Button t-Button--small t-Button--hot" href="'' ||',
'        apex_page.get_url(p_page=>14, p_clear_cache=>''14'',',
'          p_items=>''P14_APPOINTMENT_ID'',',
'          p_values=>a.APPOINTMENT_ID) || ''">Start Visit</a>''',
'      WHEN v.VISIT_ID IS NOT NULL THEN',
'        ''<a class="t-Button t-Button--small" href="'' ||',
'        apex_page.get_url(p_page=>14, p_clear_cache=>''14'',',
'          p_items=>''P14_APPOINTMENT_ID'',',
'          p_values=>a.APPOINTMENT_ID) || ''">Open Workspace</a>''',
'    END AS CREATED_AT',
'FROM APPOINTMENTS a',
'JOIN APPOINTMENT_STATUSES s ON s.STATUS_ID = a.STATUS_ID',
'LEFT JOIN PATIENT_VISITS v ON v.APPOINTMENT_ID = a.APPOINTMENT_ID',
'WHERE a.PATIENT_ID = :P10_PATIENT_ID',
'ORDER BY a.APPOINTMENT_DATE DESC, a.APPOINTMENT_TIME DESC'))
,p_plug_source_type=>'NATIVE_IG'
,p_ajax_items_to_submit=>'P10_PATIENT_ID'
,p_prn_units=>'INCHES'
,p_prn_paper_size=>'LETTER'
,p_prn_width=>11
