wwv_flow_imp_page.create_report_region(
 p_id=>wwv_flow_imp.id(8688041459962830)
,p_name=>'Patient Information'
,p_static_id=>'patient-information'
,p_title=>'Patient Information'
,p_template=>2042159785845301134
,p_display_sequence=>40
,p_region_css_classes=>'t-Alert--colorBG t-Alert--horizontal'
,p_region_template_options=>'#DEFAULT#:t-Alert--horizontal:t-Alert--defaultIcons:t-Alert--warning'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT field_label AS "Patient Detail",',
'       field_value AS "Value"',
'FROM (',
'    SELECT 1 sort_order, ''Patient Name'' field_label, FULL_NAME field_value',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
'    UNION ALL',
'    SELECT 2, ''Civil ID'', CIVIL_ID',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
'    UNION ALL',
'    SELECT 3, ''Age'', TO_CHAR(TRUNC(MONTHS_BETWEEN(SYSDATE, DATE_OF_BIRTH) / 12))',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
'    UNION ALL',
'    SELECT 4, ''Gender'', GENDER',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
'    UNION ALL',
'    SELECT 5, ''Date of Birth'', TO_CHAR(DATE_OF_BIRTH, ''DD-MON-YYYY'')',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
'    UNION ALL',
'    SELECT 6, ''Blood Group'', BLOOD_GROUP',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
'    UNION ALL',
'    SELECT 7, ''Mobile Number'', MOBILE_NO',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
'    UNION ALL',
'    SELECT 8, ''Email'', NVL(EMAIL, ''-'')',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
'    UNION ALL',
'    SELECT 9, ''Address'', NVL(ADDRESS, ''-'')',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
'    UNION ALL',
'    SELECT 10, ''Emergency Contact'', NVL(EMERGENCY_CONTACT_NAME, ''-'')',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
'    UNION ALL',
'    SELECT 11, ''Emergency Number'', NVL(EMERGENCY_CONTACT_NO, ''-'')',
'      FROM PATIENTS WHERE PATIENT_ID = :P10_PATIENT_ID',
')',
'ORDER BY sort_order'))
,p_display_condition_type=>'NEVER'
,p_ajax_enabled=>'Y'
,p_ajax_items_to_submit=>'P10_PATIENT_ID'
,p_lazy_loading=>false
,p_query_row_template=>2540130677583398057
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_csv_output=>'N'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_strip_html=>'N'
);
