 p_id=>wwv_flow_imp.id(8689331091962843)
,p_plug_name=>'Visit History'
,p_static_id=>'visit-history'
,p_title=>'Visit History'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>60
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    v.VISIT_ID,',
'    v.PATIENT_ID,',
'    v.VISIT_DATE,',
'    v.DOCTOR_ID,',
'    v.SYMPTOMS,',
'    v.DIAGNOSIS,',
'    CASE WHEN p.PRESCRIPTION_ID IS NULL',
'         THEN NVL(v.NOTES, ''No Prescription'')',
'         ELSE NVL(v.NOTES, ''Prescription Available'') END AS NOTES,',
'    v.FOLLOW_UP_DATE',
'FROM PATIENT_VISITS v',
'LEFT JOIN PRESCRIPTIONS p ON p.VISIT_ID = v.VISIT_ID',
'WHERE v.PATIENT_ID = :P10_PATIENT_ID',
'ORDER BY v.VISIT_DATE DESC'))
,p_plug_source_type=>'NATIVE_IG'
