wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(9100000000000010)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'P10 Load and Validate Patient'
,p_static_id=>'p10-load-and-validate-patient'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  IF :P10_PATIENT_ID IS NULL THEN',
'    :P10_PATIENT_NAME := NULL;',
'    :P10_CIVIL_ID := NULL;',
'    :P10_DATE_OF_BIRTH := NULL;',
'    :P10_AGE := NULL;',
'    :P10_GENDER := NULL;',
'    :P10_BLOOD_GROUP := NULL;',
'    :P10_MOBILE_NO := NULL;',
'    :P10_EMAIL := NULL;',
'    :P10_ADDRESS := NULL;',
'    :P10_EMERGENCY_CONTACT_NAME := NULL;',
'    :P10_EMERGENCY_CONTACT_NO := NULL;',
'    :P10_CREATED_AT := NULL;',
'  ELSE',
'    BEGIN',
'      SELECT FULL_NAME, CIVIL_ID, DATE_OF_BIRTH,',
'             TRUNC(MONTHS_BETWEEN(SYSDATE, DATE_OF_BIRTH) / 12),',
'             GENDER, BLOOD_GROUP, MOBILE_NO, EMAIL, ADDRESS,',
'             EMERGENCY_CONTACT_NAME, EMERGENCY_CONTACT_NO, CREATED_AT',
'        INTO :P10_PATIENT_NAME, :P10_CIVIL_ID, :P10_DATE_OF_BIRTH, :P10_AGE,',
'             :P10_GENDER, :P10_BLOOD_GROUP, :P10_MOBILE_NO, :P10_EMAIL,',
'             :P10_ADDRESS, :P10_EMERGENCY_CONTACT_NAME,',
'             :P10_EMERGENCY_CONTACT_NO, :P10_CREATED_AT',
'        FROM PATIENTS',
'       WHERE PATIENT_ID = :P10_PATIENT_ID;',
'    EXCEPTION',
'      WHEN NO_DATA_FOUND THEN',
'        :P10_PATIENT_ID := NULL;',
'        raise_application_error(-20001, ''The selected patient does not exist.'');',
'    END;',
'  END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>9100000000000010
);
end;
