wwv_flow_imp_page.create_report_region(
 p_id=>wwv_flow_imp.id(9200000000001201)
,p_name=>'Patient and Visit Summary'
,p_static_id=>'patient-visit-summary'
,p_title=>'PATIENT AND VISIT SUMMARY'
,p_template=>2042159785845301134
,p_display_sequence=>15
,p_region_template_options=>'#DEFAULT#:t-Alert--horizontal:t-Alert--defaultIcons'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT detail_label AS "Detail", detail_value AS "Value" FROM (',
'  SELECT 1 seq, ''Patient'' detail_label, p.FULL_NAME detail_value',
'    FROM PATIENTS p WHERE p.PATIENT_ID = :P12_PATIENT_ID',
'  UNION ALL SELECT 2, ''Civil ID'', p.CIVIL_ID FROM PATIENTS p WHERE p.PATIENT_ID = :P12_PATIENT_ID',
'  UNION ALL SELECT 3, ''Age'', TO_CHAR(TRUNC(MONTHS_BETWEEN(SYSDATE,p.DATE_OF_BIRTH)/12)) FROM PATIENTS p WHERE p.PATIENT_ID = :P12_PATIENT_ID',
'  UNION ALL SELECT 4, ''Gender'', p.GENDER FROM PATIENTS p WHERE p.PATIENT_ID = :P12_PATIENT_ID',
'  UNION ALL SELECT 5, ''Blood Group'', p.BLOOD_GROUP FROM PATIENTS p WHERE p.PATIENT_ID = :P12_PATIENT_ID',
'  UNION ALL SELECT 6, ''Mobile'', p.MOBILE_NO FROM PATIENTS p WHERE p.PATIENT_ID = :P12_PATIENT_ID',
'  UNION ALL SELECT 7, ''Appointment Date'', TO_CHAR(a.APPOINTMENT_DATE,''DD-MON-YYYY'') FROM APPOINTMENTS a WHERE a.APPOINTMENT_ID = :P12_APPOINTMENT_ID',
'  UNION ALL SELECT 8, ''Appointment Time'', a.APPOINTMENT_TIME FROM APPOINTMENTS a WHERE a.APPOINTMENT_ID = :P12_APPOINTMENT_ID',
'  UNION ALL SELECT 9, ''Status'', s.STATUS_NAME FROM APPOINTMENTS a JOIN APPOINTMENT_STATUSES s ON s.STATUS_ID=a.STATUS_ID WHERE a.APPOINTMENT_ID=:P12_APPOINTMENT_ID',
'  UNION ALL SELECT 10, ''Reason'', a.REASON_FOR_VISIT FROM APPOINTMENTS a WHERE a.APPOINTMENT_ID=:P12_APPOINTMENT_ID',
'  UNION ALL SELECT 11, ''Doctor'', d.FULL_NAME FROM APPOINTMENTS a JOIN DOCTORS d ON d.DOCTOR_ID=a.DOCTOR_ID WHERE a.APPOINTMENT_ID=:P12_APPOINTMENT_ID',
'  UNION ALL SELECT 12, ''Department'', dep.DEPARTMENT_NAME FROM APPOINTMENTS a JOIN DOCTORS d ON d.DOCTOR_ID=a.DOCTOR_ID JOIN DEPARTMENTS dep ON dep.DEPARTMENT_ID=d.DEPARTMENT_ID WHERE a.APPOINTMENT_ID=:P12_APPOINTMENT_ID',
'  UNION ALL SELECT 13, ''Specialty'', ds.SPECIALTY_NAME FROM APPOINTMENTS a JOIN DOCTORS d ON d.DOCTOR_ID=a.DOCTOR_ID JOIN DOCTOR_SPECIALTIES ds ON ds.SPECIALTY_ID=d.SPECIALTY_ID WHERE a.APPOINTMENT_ID=:P12_APPOINTMENT_ID',
'  UNION ALL SELECT 14, ''Visit Date'', TO_CHAR(v.VISIT_DATE,''DD-MON-YYYY'') FROM PATIENT_VISITS v WHERE v.APPOINTMENT_ID=:P12_APPOINTMENT_ID',
'  UNION ALL SELECT 15, ''Symptoms'', v.SYMPTOMS FROM PATIENT_VISITS v WHERE v.APPOINTMENT_ID=:P12_APPOINTMENT_ID',
'  UNION ALL SELECT 16, ''Diagnosis'', v.DIAGNOSIS FROM PATIENT_VISITS v WHERE v.APPOINTMENT_ID=:P12_APPOINTMENT_ID',
'  UNION ALL SELECT 17, ''Follow-up'', TO_CHAR(v.FOLLOW_UP_DATE,''DD-MON-YYYY'') FROM PATIENT_VISITS v WHERE v.APPOINTMENT_ID=:P12_APPOINTMENT_ID',
') ORDER BY seq'))
,p_ajax_enabled=>'Y'
,p_ajax_items_to_submit=>'P12_PATIENT_ID,P12_APPOINTMENT_ID'
,p_lazy_loading=>false
,p_query_row_template=>2540130677583398057
,p_query_num_rows=>20
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_csv_output=>'N'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_strip_html=>'N'
);
