wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(7890898911819242)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'P12 Create or Save Prescription'
,p_static_id=>'p12-create-save-prescription'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_count PLS_INTEGER;',
'BEGIN',
'  IF :P12_VISIT_ID IS NULL THEN',
'    raise_application_error(-20003, ''Create the patient visit before creating a prescription.'');',
'  END IF;',
'  IF :P12_PRESCRIPTION_DATE IS NULL THEN',
'    raise_application_error(-20004, ''Prescription date is required.'');',
'  END IF;',
'  IF :P12_PRESCRIPTION_ID IS NULL THEN',
'    SELECT COUNT(*) INTO l_count FROM PRESCRIPTIONS WHERE VISIT_ID=:P12_VISIT_ID;',
'    IF l_count > 0 THEN raise_application_error(-20005, ''A prescription already exists for this visit.''); END IF;',
'    INSERT INTO PRESCRIPTIONS (VISIT_ID,PATIENT_ID,DOCTOR_ID,PRESCRIPTION_DATE,NOTES)',
'    VALUES (:P12_VISIT_ID,:P12_PATIENT_ID,:P12_DOCTOR_ID,:P12_PRESCRIPTION_DATE,:P12_PRESCRIPTION_NOTES)',
'    RETURNING PRESCRIPTION_ID INTO :P12_PRESCRIPTION_ID;',
'  ELSE',
'    UPDATE PRESCRIPTIONS SET PRESCRIPTION_DATE=:P12_PRESCRIPTION_DATE, NOTES=:P12_PRESCRIPTION_NOTES',
'     WHERE PRESCRIPTION_ID=:P12_PRESCRIPTION_ID AND VISIT_ID=:P12_VISIT_ID;',
'  END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(7890783224819241)
,p_process_success_message=>'Prescription saved successfully.'
,p_internal_uid=>7890898911819242
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(7890396764819237)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'P12 Create or Save Visit'
,p_static_id=>'p12-create-save-visit'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_count PLS_INTEGER;',
'  l_patient_id APPOINTMENTS.PATIENT_ID%TYPE;',
'  l_doctor_id APPOINTMENTS.DOCTOR_ID%TYPE;',
'  l_status APPOINTMENT_STATUSES.STATUS_NAME%TYPE;',
'BEGIN',
'  SELECT a.PATIENT_ID,a.DOCTOR_ID,s.STATUS_NAME INTO l_patient_id,l_doctor_id,l_status',
'    FROM APPOINTMENTS a JOIN APPOINTMENT_STATUSES s ON s.STATUS_ID=a.STATUS_ID',
'   WHERE a.APPOINTMENT_ID=:P12_APPOINTMENT_ID;',
'  IF l_patient_id<>:P12_PATIENT_ID OR l_doctor_id<>:P12_DOCTOR_ID THEN',
'    raise_application_error(-20006, ''The appointment context is invalid.'');',
'  END IF;',
'  IF :P12_VISIT_DATE IS NULL THEN raise_application_error(-20007, ''Visit date is required.''); END IF;',
'  IF :P12_FOLLOW_UP_DATE IS NOT NULL AND :P12_FOLLOW_UP_DATE<:P12_VISIT_DATE THEN',
'    raise_application_error(-20008, ''Follow-up date cannot be earlier than visit date.'');',
'  END IF;',
'  IF :P12_VISIT_ID IS NULL THEN',
'    IF l_status=''Cancelled'' THEN raise_application_error(-20009, ''A cancelled appointment cannot create a visit.''); END IF;',
'    SELECT COUNT(*) INTO l_count FROM PATIENT_VISITS WHERE APPOINTMENT_ID=:P12_APPOINTMENT_ID;',
'    IF l_count>0 THEN raise_application_error(-20010, ''A patient visit already exists for this appointment.''); END IF;',
'    INSERT INTO PATIENT_VISITS (APPOINTMENT_ID,PATIENT_ID,DOCTOR_ID,VISIT_DATE,SYMPTOMS,DIAGNOSIS,NOTES,FOLLOW_UP_DATE)',
'    VALUES (:P12_APPOINTMENT_ID,:P12_PATIENT_ID,:P12_DOCTOR_ID,:P12_VISIT_DATE,:P12_SYMPTOMS,:P12_DIAGNOSIS,:P12_NOTES,:P12_FOLLOW_UP_DATE)',
'    RETURNING VISIT_ID INTO :P12_VISIT_ID;',
'  ELSE',
'    UPDATE PATIENT_VISITS SET VISIT_DATE=:P12_VISIT_DATE,SYMPTOMS=:P12_SYMPTOMS,DIAGNOSIS=:P12_DIAGNOSIS,',
'      NOTES=:P12_NOTES,FOLLOW_UP_DATE=:P12_FOLLOW_UP_DATE',
'     WHERE VISIT_ID=:P12_VISIT_ID AND APPOINTMENT_ID=:P12_APPOINTMENT_ID AND PATIENT_ID=:P12_PATIENT_ID;',
'  END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(7889499576819228)
,p_process_success_message=>'Visit saved successfully.'
,p_internal_uid=>7890396764819237
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(9200000000001220)
,p_process_sequence=>5
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'P12 Initialize Clinical Context'
,p_static_id=>'p12-initialize-clinical-context'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_patient_id APPOINTMENTS.PATIENT_ID%TYPE;',
'BEGIN',
'  IF :P12_PATIENT_ID IS NULL OR :P12_APPOINTMENT_ID IS NULL THEN',
'    apex_error.add_error(',
'      p_message=>''Open this page from an appointment in Patient Profile.'',',
'      p_display_location=>apex_error.c_inline_in_notification);',
'    RETURN;',
'  END IF;',
'  BEGIN',
'    SELECT a.PATIENT_ID,a.DOCTOR_ID,p.FULL_NAME,d.FULL_NAME',
'      INTO l_patient_id,:P12_DOCTOR_ID,:P12_PATIENT_NAME,:P12_DOCTOR_NAME',
'      FROM APPOINTMENTS a JOIN PATIENTS p ON p.PATIENT_ID=a.PATIENT_ID',
'      JOIN DOCTORS d ON d.DOCTOR_ID=a.DOCTOR_ID',
'     WHERE a.APPOINTMENT_ID=:P12_APPOINTMENT_ID;',
'  EXCEPTION WHEN NO_DATA_FOUND THEN',
'    apex_error.add_error(',
'      p_message=>''The selected appointment no longer exists.'',',
'      p_display_location=>apex_error.c_inline_in_notification);',
'    RETURN;',
'  END;',
'  IF l_patient_id<>:P12_PATIENT_ID THEN',
'    apex_error.add_error(',
'      p_message=>''The selected appointment does not belong to this patient.'',',
'      p_display_location=>apex_error.c_inline_in_notification);',
'    RETURN;',
'  END IF;',
'  BEGIN',
'    SELECT VISIT_ID,VISIT_DATE,SYMPTOMS,DIAGNOSIS,NOTES,FOLLOW_UP_DATE',
'      INTO :P12_VISIT_ID,:P12_VISIT_DATE,:P12_SYMPTOMS,:P12_DIAGNOSIS,:P12_NOTES,:P12_FOLLOW_UP_DATE',
'      FROM PATIENT_VISITS WHERE APPOINTMENT_ID=:P12_APPOINTMENT_ID;',
'  EXCEPTION WHEN NO_DATA_FOUND THEN :P12_VISIT_ID:=NULL; :P12_VISIT_DATE:=SYSDATE; END;',
'  IF :P12_VISIT_ID IS NOT NULL THEN',
'    BEGIN',
'      SELECT PRESCRIPTION_ID,PRESCRIPTION_DATE,NOTES',
'        INTO :P12_PRESCRIPTION_ID,:P12_PRESCRIPTION_DATE,:P12_PRESCRIPTION_NOTES',
'        FROM PRESCRIPTIONS WHERE VISIT_ID=:P12_VISIT_ID;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN :P12_PRESCRIPTION_ID:=NULL; :P12_PRESCRIPTION_DATE:=SYSDATE; END;',
'  ELSE',
