 p_id=>wwv_flow_imp.id(9500000000001460)
,p_name=>'Previous Visits'
,p_static_id=>'previous-visits'
,p_title=>'Previous Visits'
,p_template=>4073835273271169698
,p_display_sequence=>50
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT v.VISIT_ID, TO_CHAR(v.VISIT_DATE,''DD-MON-YYYY'') VISIT_DATE,',
'       d.FULL_NAME DOCTOR_NAME, v.SYMPTOMS, v.DIAGNOSIS, v.NOTES,',
'       TO_CHAR(v.FOLLOW_UP_DATE,''DD-MON-YYYY'') FOLLOW_UP_DATE',
'  FROM PATIENT_VISITS v',
'  JOIN DOCTORS d ON d.DOCTOR_ID = v.DOCTOR_ID',
' WHERE v.PATIENT_ID = :P14_PATIENT_ID',
'   AND v.APPOINTMENT_ID <> :P14_APPOINTMENT_ID',
' ORDER BY v.VISIT_DATE DESC'))
,p_header=>'Reviews earlier visits, diagnoses, notes, and follow-up history.'
,p_ajax_enabled=>'Y'
,p_ajax_items_to_submit=>'P14_APPOINTMENT_ID,P14_PATIENT_ID,P14_DOCTOR_ID'
