wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(8030396764819237)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'P14 Create or Save Visit'
,p_static_id=>'p14-create-save-visit'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_count PLS_INTEGER;',
'  l_patient_id APPOINTMENTS.PATIENT_ID%TYPE;',
'  l_doctor_id APPOINTMENTS.DOCTOR_ID%TYPE;',
'  l_status APPOINTMENT_STATUSES.STATUS_NAME%TYPE;',
'BEGIN',
'  SELECT a.PATIENT_ID,a.DOCTOR_ID,s.STATUS_NAME INTO l_patient_id,l_doctor_id,l_status',
'    FROM APPOINTMENTS a JOIN APPOINTMENT_STATUSES s ON s.STATUS_ID=a.STATUS_ID',
'   WHERE a.APPOINTMENT_ID=:P14_APPOINTMENT_ID;',
'  IF l_patient_id<>:P14_PATIENT_ID OR l_doctor_id<>:P14_DOCTOR_ID THEN',
'    raise_application_error(-20006, ''The appointment context is invalid.'');',
'  END IF;',
'  IF :P14_VISIT_DATE IS NULL THEN raise_application_error(-20007, ''Visit date is required.''); END IF;',
'  IF :P14_FOLLOW_UP_DATE IS NOT NULL AND :P14_FOLLOW_UP_DATE<:P14_VISIT_DATE THEN',
'    raise_application_error(-20008, ''Follow-up date cannot be earlier than visit date.'');',
'  END IF;',
'  IF :P14_VISIT_ID IS NULL THEN',
'    IF l_status=''Cancelled'' THEN raise_application_error(-20009, ''A cancelled appointment cannot create a visit.''); END IF;',
'    SELECT COUNT(*) INTO l_count FROM PATIENT_VISITS WHERE APPOINTMENT_ID=:P14_APPOINTMENT_ID;',
'    IF l_count>0 THEN raise_application_error(-20010, ''A patient visit already exists for this appointment.''); END IF;',
'    INSERT INTO PATIENT_VISITS (APPOINTMENT_ID,PATIENT_ID,DOCTOR_ID,VISIT_DATE,SYMPTOMS,DIAGNOSIS,NOTES,FOLLOW_UP_DATE)',
'    VALUES (:P14_APPOINTMENT_ID,:P14_PATIENT_ID,:P14_DOCTOR_ID,:P14_VISIT_DATE,:P14_SYMPTOMS,:P14_DIAGNOSIS,:P14_NOTES,:P14_FOLLOW_UP_DATE)',
'    RETURNING VISIT_ID INTO :P14_VISIT_ID;',
'  ELSE',
'    UPDATE PATIENT_VISITS SET VISIT_DATE=:P14_VISIT_DATE,SYMPTOMS=:P14_SYMPTOMS,DIAGNOSIS=:P14_DIAGNOSIS,',
'      NOTES=:P14_NOTES,FOLLOW_UP_DATE=:P14_FOLLOW_UP_DATE',
'     WHERE VISIT_ID=:P14_VISIT_ID AND APPOINTMENT_ID=:P14_APPOINTMENT_ID AND PATIENT_ID=:P14_PATIENT_ID;',
'  END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(8029499576819228)
,p_process_success_message=>'Visit saved successfully.'
,p_internal_uid=>8030396764819237
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(9340000000001220)
,p_process_sequence=>5
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'P14 Initialize Clinical Context'
,p_static_id=>'p14-initialize-clinical-context'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_status APPOINTMENT_STATUSES.STATUS_NAME%TYPE;',
'BEGIN',
'  IF :P14_APPOINTMENT_ID IS NULL THEN',
'    apex_error.add_error(p_message=>''Open this page from an appointment.'',p_display_location=>apex_error.c_inline_in_notification);',
'    RETURN;',
'  END IF;',
'  BEGIN',
'    SELECT a.PATIENT_ID,a.DOCTOR_ID,p.FULL_NAME,d.FULL_NAME,s.STATUS_NAME',
'      INTO :P14_PATIENT_ID,:P14_DOCTOR_ID,:P14_PATIENT_NAME,:P14_DOCTOR_NAME,l_status',
'      FROM APPOINTMENTS a JOIN PATIENTS p ON p.PATIENT_ID=a.PATIENT_ID',
'      JOIN DOCTORS d ON d.DOCTOR_ID=a.DOCTOR_ID',
'      JOIN APPOINTMENT_STATUSES s ON s.STATUS_ID=a.STATUS_ID',
'     WHERE a.APPOINTMENT_ID=:P14_APPOINTMENT_ID;',
'  EXCEPTION WHEN NO_DATA_FOUND THEN',
'    apex_error.add_error(',
'      p_message=>''The selected appointment no longer exists.'',',
'      p_display_location=>apex_error.c_inline_in_notification);',
'    RETURN;',
'  END;',
'  IF l_status = ''Cancelled'' THEN',
'    apex_error.add_error(p_message=>''A cancelled appointment cannot be used for a clinical visit.'',p_display_location=>apex_error.c_inline_in_notification);',
'    RETURN;',
'  END IF;',
'  BEGIN',
'    SELECT VISIT_ID,VISIT_DATE,SYMPTOMS,DIAGNOSIS,NOTES,FOLLOW_UP_DATE',
'      INTO :P14_VISIT_ID,:P14_VISIT_DATE,:P14_SYMPTOMS,:P14_DIAGNOSIS,:P14_NOTES,:P14_FOLLOW_UP_DATE',
'      FROM PATIENT_VISITS WHERE APPOINTMENT_ID=:P14_APPOINTMENT_ID;',
'  EXCEPTION WHEN NO_DATA_FOUND THEN :P14_VISIT_ID:=NULL; :P14_VISIT_DATE:=SYSDATE; END;',
'  IF :P14_VISIT_ID IS NOT NULL THEN',
'    BEGIN',
'      SELECT PRESCRIPTION_ID,PRESCRIPTION_DATE,NOTES',
'        INTO :P14_PRESCRIPTION_ID,:P14_PRESCRIPTION_DATE,:P14_PRESCRIPTION_NOTES',
'        FROM PRESCRIPTIONS WHERE VISIT_ID=:P14_VISIT_ID;',
'    EXCEPTION WHEN NO_DATA_FOUND THEN :P14_PRESCRIPTION_ID:=NULL; :P14_PRESCRIPTION_DATE:=SYSDATE; END;',
'  ELSE',
'    :P14_PRESCRIPTION_ID:=NULL; :P14_PRESCRIPTION_DATE:=SYSDATE;',
'  END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>9340000000001220
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(9500000000001490)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_region_id=>wwv_flow_imp.id(8030995125819243)
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'P14 Save Prescribed Medicines'
,p_static_id=>'p14-save-prescribed-medicines'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  IF :P14_PRESCRIPTION_ID IS NULL THEN',
'    raise_application_error(-20011, ''Save the prescription before adding medicines.'');',
'  END IF;',
'  CASE :APEX$ROW_STATUS',
'    WHEN ''C'' THEN',
'      INSERT INTO PRESCRIPTION_ITEMS (PRESCRIPTION_ID,MEDICINE_ID,DOSAGE,FREQUENCY,DURATION_DAYS,INSTRUCTIONS)',
'      VALUES (:P14_PRESCRIPTION_ID,:MEDICINE_ID,:DOSAGE,:FREQUENCY,:DURATION_DAYS,:INSTRUCTIONS)',
'      RETURNING PRESCRIPTION_ITEM_ID INTO :PRESCRIPTION_ITEM_ID;',
'    WHEN ''U'' THEN',
'      UPDATE PRESCRIPTION_ITEMS SET MEDICINE_ID=:MEDICINE_ID,DOSAGE=:DOSAGE,FREQUENCY=:FREQUENCY,',
'        DURATION_DAYS=:DURATION_DAYS,INSTRUCTIONS=:INSTRUCTIONS',
'       WHERE PRESCRIPTION_ITEM_ID=:PRESCRIPTION_ITEM_ID AND PRESCRIPTION_ID=:P14_PRESCRIPTION_ID;',
'    WHEN ''D'' THEN',
'      DELETE FROM PRESCRIPTION_ITEMS WHERE PRESCRIPTION_ITEM_ID=:PRESCRIPTION_ITEM_ID',
'       AND PRESCRIPTION_ID=:P14_PRESCRIPTION_ID;',
'  END CASE;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>9500000000001490
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(8420239350410304)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_region_id=>wwv_flow_imp.id(8030995125819243)
,p_process_type=>'NATIVE_IG_DML'
,p_process_name=>unistr('Prescription Items \2014 Add Medicines - Save Interactive Grid Data')
,p_static_id=>'prescription-items-add-medicines-save-interactive-grid-data'
