,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT A.ADMISSION_ID,',
'       P.FULL_NAME      AS PATIENT_NAME,',
'       DR.FULL_NAME     AS DOCTOR_NAME,',
'       R.ROOM_NO,',
'       R.ROOM_TYPE,',
'       A.ADMISSION_DATE,',
'       A.DISCHARGE_DATE,',
'       A.ADMISSION_REASON,',
'       A.STATUS,',
'       CASE WHEN A.DISCHARGE_DATE IS NOT NULL',
'            THEN TRUNC(A.DISCHARGE_DATE - A.ADMISSION_DATE)',
'            ELSE TRUNC(SYSDATE - A.ADMISSION_DATE) END AS DAYS_ADMITTED',
'FROM   ADMISSIONS A',
'JOIN   PATIENTS P  ON A.PATIENT_ID = P.PATIENT_ID',
'JOIN   DOCTORS  DR ON A.DOCTOR_ID  = DR.DOCTOR_ID',
'JOIN   ROOMS    R  ON A.ROOM_ID    = R.ROOM_ID',
'ORDER  BY A.ADMISSION_DATE DESC'))
