,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Update Room Status After Admission Change'
,p_static_id=>'update-room-status-after-admission-change'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'    IF :P17_STATUS = ''Admitted'' THEN',
'        UPDATE ROOMS',
'        SET    STATUS = ''Occupied''',
'        WHERE  ROOM_ID = :P17_ROOM_ID;',
'    ELSIF :P17_STATUS = ''Discharged''',
'          AND :P17_DISCHARGE_DATE IS NOT NULL THEN',
'        UPDATE ROOMS',
'        SET    STATUS = ''Available''',
'        WHERE  ROOM_ID = :P17_ROOM_ID;',
'    END IF;',
'    COMMIT;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>8304875334498318
,p_created_on=>wwv_flow_imp.dz('20260714101426Z')
,p_updated_on=>wwv_flow_imp.dz('20260714101426Z')
,p_created_by=>'ADMIN'
,p_updated_by=>'ADMIN'
);
end;
