wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(8348182644418863)
,p_plug_name=>'Appointment Report'
,p_static_id=>'appointment-report'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>30
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT A.APPOINTMENT_ID,',
'       P.FULL_NAME      AS PATIENT_NAME,',
'       DR.FULL_NAME     AS DOCTOR_NAME,',
'       DEP.DEPARTMENT_NAME,',
'       A.APPOINTMENT_DATE,',
'       A.APPOINTMENT_TIME,',
'       S.STATUS_NAME,',
'       A.REASON_FOR_VISIT,',
'       A.CREATED_AT',
'FROM   APPOINTMENTS A',
'JOIN   PATIENTS           P   ON A.PATIENT_ID    = P.PATIENT_ID',
'JOIN   DOCTORS            DR  ON A.DOCTOR_ID     = DR.DOCTOR_ID',
'JOIN   DEPARTMENTS        DEP ON DR.DEPARTMENT_ID = DEP.DEPARTMENT_ID',
'JOIN   APPOINTMENT_STATUSES S ON A.STATUS_ID     = S.STATUS_ID',
'WHERE  (:P18_DATE_FROM     IS NULL OR A.APPOINTMENT_DATE  >= :P18_DATE_FROM)',
'AND    (:P18_DATE_TO       IS NULL OR A.APPOINTMENT_DATE  <= :P18_DATE_TO)',
'AND    (:P18_DEPT_FILTER   IS NULL OR DEP.DEPARTMENT_ID   = :P18_DEPT_FILTER)',
'AND    (:P18_DOCTOR_FILTER IS NULL OR DR.DOCTOR_ID        = :P18_DOCTOR_FILTER)',
'AND    (:P18_STATUS_FILTER IS NULL OR A.STATUS_ID         = :P18_STATUS_FILTER)',
'ORDER  BY A.APPOINTMENT_DATE DESC'))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P18_DATE_FROM,P18_DATE_TO,P18_DEPT_FILTER,P18_DOCTOR_FILTER,P18_STATUS_FILTER'
