,p_plug_name=>'Patient Visit Report'
,p_static_id=>'patient-visit-report'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>40
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT P.FULL_NAME       AS PATIENT_NAME,',
'       DR.FULL_NAME      AS DOCTOR_NAME,',
'       DR.NATIONALITY    AS DOCTOR_NATIONALITY,',
'       DEP.DEPARTMENT_NAME,',
'       V.VISIT_DATE,',
'       V.SYMPTOMS,',
'       V.DIAGNOSIS,',
'       V.NOTES,',
'       V.FOLLOW_UP_DATE',
'FROM   PATIENT_VISITS V',
'JOIN   PATIENTS    P   ON V.PATIENT_ID    = P.PATIENT_ID',
'JOIN   DOCTORS     DR  ON V.DOCTOR_ID     = DR.DOCTOR_ID',
'JOIN   DEPARTMENTS DEP ON DR.DEPARTMENT_ID = DEP.DEPARTMENT_ID',
'WHERE  (:P19_DOCTOR_FILTER IS NULL OR DR.DOCTOR_ID     = :P19_DOCTOR_FILTER)',
'AND    (:P19_DEPT_FILTER   IS NULL OR DR.DEPARTMENT_ID = :P19_DEPT_FILTER)',
'AND    (:P19_DATE_FROM     IS NULL OR V.VISIT_DATE     >= :P19_DATE_FROM)',
'AND    (:P19_DATE_TO       IS NULL OR V.VISIT_DATE     <= :P19_DATE_TO)',
'ORDER  BY V.VISIT_DATE DESC'))
