,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT M.MEDICINE_NAME,',
'       C.CATEGORY_NAME,',
'       M.UNIT,',
'       M.CURRENT_STOCK,',
'       M.REORDER_LEVEL,',
'       M.CURRENT_STOCK - M.REORDER_LEVEL  AS STOCK_DIFFERENCE,',
'       CASE WHEN M.CURRENT_STOCK < M.REORDER_LEVEL',
'            THEN ''Low Stock'' ELSE ''Normal'' END AS STOCK_STATUS,',
'       M.STATUS',
'FROM   MEDICINES M',
'JOIN   MEDICINE_CATEGORIES C ON M.CATEGORY_ID = C.CATEGORY_ID',
'ORDER  BY STOCK_STATUS DESC, M.MEDICINE_NAME'))
