wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(8372424727588945)
,p_plug_name=>'Admission Report'
,p_static_id=>'admission-report'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>10
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT P.FULL_NAME      AS PATIENT_NAME,',
'       P.CIVIL_ID,',
'       DR.FULL_NAME     AS DOCTOR_NAME,',
'       R.ROOM_NO,',
'       R.ROOM_TYPE,',
'       R.DAILY_RATE,',
'       A.ADMISSION_DATE,',
'       A.DISCHARGE_DATE,',
'       CASE WHEN A.DISCHARGE_DATE IS NOT NULL',
'            THEN TRUNC(A.DISCHARGE_DATE - A.ADMISSION_DATE)',
'            ELSE TRUNC(SYSDATE - A.ADMISSION_DATE) END  AS DAYS_ADMITTED,',
'       CASE WHEN A.DISCHARGE_DATE IS NOT NULL',
'            THEN TRUNC(A.DISCHARGE_DATE - A.ADMISSION_DATE) * R.DAILY_RATE',
'            ELSE TRUNC(SYSDATE - A.ADMISSION_DATE) * R.DAILY_RATE END AS TOTAL_COST,',
'       A.ADMISSION_REASON,',
'       A.STATUS',
'FROM   ADMISSIONS A',
'JOIN   PATIENTS P  ON A.PATIENT_ID = P.PATIENT_ID',
'JOIN   DOCTORS  DR ON A.DOCTOR_ID  = DR.DOCTOR_ID',
'JOIN   ROOMS    R  ON A.ROOM_ID    = R.ROOM_ID',
'ORDER  BY A.ADMISSION_DATE DESC'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_content_disposition=>'ATTACHMENT'
